### The Deobfuscated Code

```javascript
// --- CONFIGURATION ---
const Config = {
    repulsion: 4000,
    springK: 0.004,
    damping: 0.92,
    gravity: 0.0003,
    particleMax: 40,
    particleFade: 0.04,
    cameraEase: 0.06
};

// --- ENTITIES (NODES) ---
const nodes = [
    { id: 'Hub',     label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: 'alpha',   label: 'alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: 'beta',    label: 'beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: 'gamma',   label: 'gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: 'delta',   label: 'delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: 'epsilon', label: 'epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// --- RELATIONSHIPS (SPRINGS) ---
const links = [
    { a: 'Hub',   b: 'alpha',   rest: 160, k: 0.006 },
    { a: 'Hub',   b: 'beta',    rest: 160, k: 0.005 },
    { a: 'Hub',   b: 'gamma',   rest: 170, k: 0.004 },
    { a: 'Hub',   b: 'delta',   rest: 170, k: 0.004 },
    { a: 'Hub',   b: 'epsilon', rest: 180, k: 0.003 },
    { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
    { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
    { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

// --- STATE VARIABLES ---
let currentCamera = { x: 400, y: 300, zoom: 1 };
let targetCamera  = { x: 400, y: 300, zoom: 1 };
let particles     = [];
let frameCount    = 0;

// --- UTILITY ---
function getNodeById(id) {
    for (let i = 0; i < nodes.length; i++) {
        if (nodes[i].id === id) return nodes[i];
    }
    return null;
}

// --- PHYSICS ENGINE ---
function updatePhysics() {
    // 1. Repel nodes from each other (Coulomb-like force)
    for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
            let dx = nodes[i].x - nodes[j].x;
            let dy = nodes[i].y - nodes[j].y;
            let dist = Math.sqrt(dx * dx + dy * dy) || 1;

            // Force decreases as distance increases
            let force = Config.repulsion / (dist * dist);
            let fx = (dx / dist) * force;
            let fy = (dy / dist) * force;

            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // 2. Attract connected nodes (Hooke's Law / Spring force)
    for (let i = 0; i < links.length; i++) {
        let nodeA = getNodeById(links[i].a);
        let nodeB = getNodeById(links[i].b);
        if (!nodeA || !nodeB) continue;

        let dx = nodeB.x - nodeA.x;
        let dy = nodeB.y - nodeA.y;
        let dist = Math.sqrt(dx * dx + dy * dy) || 1;

        // Difference between current distance and resting distance
        let displacement = dist - links[i].rest;
        let force = (links[i].k || Config.springK) * displacement;

        let fx = (dx / dist) * force;
        let fy = (dy / dist) * force;

        nodeA.vx += fx;
        nodeA.vy += fy;
        nodeB.vx -= fx;
        nodeB.vy -= fy;
    }

    // 3. Apply velocities, center-gravity, and friction
    for (let i = 0; i < nodes.length; i++) {
        let node = nodes[i];

        // Pull towards center of the screen (400, 300)
        node.vx += (400 - node.x) * Config.gravity;
        node.vy += (300 - node.y) * Config.gravity;

        // Apply damping (friction)
        node.vx *= Config.damping;
        node.vy *= Config.damping;

        // Update positions
        node.x += node.vx;
        node.y += node.vy;
    }
}

// --- PARTICLE SYSTEM ---
function emitParticles() {
    if (particles.length >= Config.particleMax) return;

    // Pick a random node to emit a particle from
    let randomNode = nodes[Math.floor(Math.random() * nodes.length)];
    let angle = Math.random() * Math.PI * 2;
    let speed = 0.3 + (Math.random() * 0.7);

    particles.push({
        x: randomNode.x,
        y: randomNode.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 50 + (Math.random() * 120),
        size: 0.8 + (Math.random() * 1.2)
    });
}

function updateParticles() {
    // Iterate backwards to safely remove items while looping
    for (let i = particles.length - 1; i >= 0; i--) {
        let p = particles[i];

        p.vx *= 0.995; // Slight air resistance
        p.vy *= 0.995;
        p.x += p.vx;
        p.y += p.vy;
        p.age++;

        if (p.age > p.maxAge) {
            particles.splice(i, 1);
        }
    }
}

// --- CAMERA SYSTEM ---
function updateCamera() {
    // Lerp (Linear Interpolate) current camera towards target camera for smooth panning/zooming
    currentCamera.x += (targetCamera.x - currentCamera.x) * Config.cameraEase;
    currentCamera.y += (targetCamera.y - currentCamera.y) * Config.cameraEase;
    currentCamera.zoom += (targetCamera.zoom - currentCamera.zoom) * Config.cameraEase;
}

// --- MAIN GAME LOOP ---
function tick() {
    updateCamera();
    updatePhysics();

    // Emit a new particle every 3 ticks
    if (frameCount % 3 === 0) {
        emitParticles();
    }
    updateParticles();

    frameCount++;
}

// Run the loop every 16ms (roughly 60 FPS)
setInterval(tick, 16);
```

### Explanation: What Does This Code Do?

This code is the **headless logic engine for a 2D Force-Directed Graph**. It calculates physics and movement for a network of nodes, but it *does not* contain any canvas rendering code (meaning it runs math in the background, likely paired with another script that draws it to an HTML canvas).

Here is a breakdown of its features:

1.  **The Graph Network:**
    It initializes a "Hub" node and 5 satellite nodes named after Greek letters (alpha, beta, gamma, delta, epsilon). These nodes are connected together via a predefined array of links.
2.  **Physics Simulation (Force-Directed Layout):**
    Every 16 milliseconds (~60 Frames Per Second), it calculates three physical forces:
    *   **Repulsion:** Nodes act like magnets with the same polarity; they constantly push away from each other so they don't overlap.
    *   **Attraction (Springs):** The links between nodes act as elastic springs. If nodes get too far apart, they snap back together. If they get closer than the spring's "rest length", they push apart.
    *   **Gravity & Friction:** A very weak gravity pulls all nodes toward the center coordinates `(400, 300)` so they don't float off-screen. A damping modifier (friction) gradually slows them down so the simulation eventually settles into a stable web shape.
3.  **Particle Emitter:**
    To add visual flair, the code routinely spawns small particles from random nodes. These particles shoot out in a random direction, slow down due to air resistance, and are deleted once they reach their maximum age (lifespan).
4.  **Smooth Camera:**
    It contains logic to track a target camera coordinate. It uses **Lerp (Linear Interpolation)** to smoothly glide the current viewpoint to the target viewpoint.

#### Note on the Obfuscation
The original code you provided was heavily obfuscated using a well-known tool (likely javascript-obfuscator). It hid the logic by:
*   Moving all strings into a Base64-encoded, shuffled array.
*   Replacing simple math (`a * b`) with function calls inside dictionaries.
*   Using **Control Flow Flattening** (putting code inside a `switch` statement hidden in an infinite `while` loop) to make the order of execution impossible to read at a glance.
